CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_emitir_evento_manchester`()
BEGIN

    INSERT INTO painel_consumo_evento (
        origem,
        id_evento,
        painel_tipo,
        id_local_operacional,
        consumido_em
    )
    SELECT 
        'FILA_OPERACIONAL_EVENTO',
        s.id_senha,
        'MANCHESTER',
        s.id_local,
        NOW()
    FROM senha s
    WHERE s.risco_dinamico_em >= NOW() - INTERVAL 5 SECOND;

END ;;
