/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_estoque_fluxo_his`(
    IN p_id_unidade BIGINT,
    IN p_id_local BIGINT,
    IN p_id_item BIGINT,
    IN p_id_lote BIGINT,
    IN p_quantidade DECIMAL(15,4),
    IN p_acao ENUM('RESERVAR','DISPENSAR','ESTORNAR_RESERVA'),
    IN p_id_referencia BIGINT,
    IN p_id_sessao BIGINT
)
BEGIN

    DECLARE v_hash CHAR(64);
    DECLARE v_fis DECIMAL(15,4);
    DECLARE v_res DECIMAL(15,4);

    -- VALIDAÇÃO DE SESSÃO
  

    IF p_id_sessao IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT='LEI_IMUTAVEL: Sessao obrigatoria';
    END IF;


    -- PIPELINE HASH IDEMPOTENTE
   

    SET v_hash = SHA2(CONCAT(
        p_id_referencia,
        p_id_item,
        p_id_lote,
        p_acao,
        p_id_sessao
    ),256);


    -- LOCK DISTRIBUÍDO (ANTI REPLAY)


    INSERT INTO estoque_execucao_pipeline(pipeline_hash,estado)
    VALUES(v_hash,'PROCESSANDO')
    ON DUPLICATE KEY UPDATE pipeline_hash=pipeline_hash;

    START TRANSACTION;

      
        -- LOCK PESSIMISTA DO SALDO
     

        SELECT qtd_fisica,qtd_reservada
        INTO v_fis,v_res
        FROM estoque_saldo
        WHERE id_unidade=p_id_unidade
        AND id_local=p_id_local
        AND id_item=p_id_item
        AND id_lote=p_id_lote
        FOR UPDATE;


        -- MATERIALIZA SALDO SE NÃO EXISTIR
   

        IF v_fis IS NULL THEN

            SET v_fis = 0;
            SET v_res = 0;

            INSERT INTO estoque_saldo
            (
                id_unidade,
                id_local,
                id_item,
                id_lote,
                qtd_fisica,
                qtd_reservada,
                id_sessao_usuario
            )
            VALUES
            (
                p_id_unidade,
                p_id_local,
                p_id_item,
                p_id_lote,
                0,
                0,
                p_id_sessao
            )
            ON DUPLICATE KEY UPDATE id_saldo=id_saldo;

        END IF;


        -- MOTOR HIS LOGÍSTICO


        CASE p_acao

            WHEN 'RESERVAR' THEN

                IF (v_fis - v_res) < p_quantidade THEN
                    ROLLBACK;
                    SIGNAL SQLSTATE '45000'
                    SET MESSAGE_TEXT='SALDO_PROJETADO_INSUFICIENTE';
                END IF;

                UPDATE estoque_saldo
                SET qtd_reservada = qtd_reservada + p_quantidade
                WHERE id_unidade=p_id_unidade
                AND id_local=p_id_local
                AND id_item=p_id_item
                AND id_lote=p_id_lote;

            WHEN 'DISPENSAR' THEN

                UPDATE estoque_saldo
                SET qtd_fisica = qtd_fisica - p_quantidade,
                    qtd_reservada = GREATEST(qtd_reservada - p_quantidade,0)
                WHERE id_unidade=p_id_unidade
                AND id_local=p_id_local
                AND id_item=p_id_item
                AND id_lote=p_id_lote;

            WHEN 'ESTORNAR_RESERVA' THEN

                UPDATE estoque_saldo
                SET qtd_reservada = GREATEST(qtd_reservada - p_quantidade,0)
                WHERE id_unidade=p_id_unidade
                AND id_local=p_id_local
                AND id_item=p_id_item
                AND id_lote=p_id_lote;

        END CASE;


        -- AUDITORIA SEMÂNTICA


        INSERT INTO estoque_audit_stream
        (
            id_referencia_externa,
            entidade_tipo,
            evento_tipo,
            payload,
            hash_pipeline
        )
        VALUES
        (
            p_id_referencia,
            'ESTOQUE',
            p_acao,
            JSON_OBJECT(
                'item',p_id_item,
                'lote',p_id_lote,
                'qtd',p_quantidade,
                'sessao',p_id_sessao
            ),
            v_hash
        );


        -- FINALIZA PIPELINE


        UPDATE estoque_execucao_pipeline
        SET estado='CONCLUIDO'
        WHERE pipeline_hash=v_hash;

    COMMIT;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_estoque_movimentar` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_estoque_movimentar`(
    IN p_id_unidade BIGINT,
    IN p_id_item BIGINT,
    IN p_id_local_origem BIGINT,
    IN p_id_local_destino BIGINT,
    IN p_id_lote BIGINT,
    IN p_quantidade DECIMAL(15,4),
    IN p_tipo_movimento VARCHAR(30),
    IN p_id_sessao BIGINT
)
BEGIN

    DECLARE v_hash CHAR(64);
    DECLARE v_saldo DECIMAL(15,4);

    IF p_id_sessao IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT='LEI_IMUTAVEL: Sessao obrigatoria';
    END IF;

    SET v_hash = SHA2(CONCAT(
        p_id_item,
        p_id_lote,
        p_quantidade,
        p_id_sessao,
        IFNULL(p_id_local_origem,0),
        IFNULL(p_id_local_destino,0)
    ),256);

    IF EXISTS (
        SELECT 1
        FROM estoque_movimento
        WHERE hash_duplicidade = v_hash
    ) THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT='ALERTA_REPLAY: Operacao ja processada';
    END IF;

    IF NOT EXISTS (
        SELECT 1
        FROM estoque_lote
        WHERE id_lote=p_id_lote
        AND id_item=p_id_item
    ) THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT='ERRO_CONSISTENCIA: Lote invalido';
    END IF;

    START TRANSACTION;

    IF p_id_local_origem IS NOT NULL THEN

        SELECT quantidade_atual
        INTO v_saldo
        FROM estoque_saldo
        WHERE id_item=p_id_item
        AND id_local=p_id_local_origem
        AND id_lote=p_id_lote
        FOR UPDATE;

        IF v_saldo IS NULL OR v_saldo < p_quantidade THEN
            ROLLBACK;
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT='ERRO_SALDO: Saldo insuficiente';
        END IF;

        UPDATE estoque_saldo
        SET quantidade_atual=quantidade_atual-p_quantidade
        WHERE id_item=p_id_item
        AND id_local=p_id_local_origem
        AND id_lote=p_id_lote;

    END IF;

    IF p_id_local_destino IS NOT NULL THEN

        INSERT INTO estoque_saldo
        (id_unidade,id_local,id_item,id_lote,quantidade_atual,id_sessao_usuario)
        VALUES
        (p_id_unidade,p_id_local_destino,p_id_item,p_id_lote,p_quantidade,p_id_sessao)

        ON DUPLICATE KEY UPDATE
        quantidade_atual=quantidade_atual+p_quantidade;

    END IF;

    INSERT INTO estoque_movimento
    (
        id_item,id_unidade,
        id_local_origem,id_local_destino,
        id_lote,tipo_movimento,
        quantidade,hash_duplicidade,id_sessao_usuario
    )
    VALUES
    (
        p_id_item,p_id_unidade,
        p_id_local_origem,p_id_local_destino,
        p_id_lote,p_tipo_movimento,
        p_quantidade,v_hash,p_id_sessao
    );

    COMMIT;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_estoque_movimentar_extremo` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_estoque_movimentar_extremo`(
    IN p_id_unidade BIGINT,
    IN p_id_item BIGINT,
    IN p_id_lote BIGINT,
    IN p_id_local_origem BIGINT,
    IN p_id_local_destino BIGINT,
    IN p_quantidade DECIMAL(15,4),
    IN p_tipo_fluxo ENUM('RESERVA', 'DISPENSACO', 'ADMINISTRACAO', 'AJUSTE'),
    IN p_id_sessao BIGINT,
    IN p_id_referencia_assistencial BIGINT -- ID da Prescrição ou FFA
)
proc_label: BEGIN
    DECLARE v_pipeline_hash CHAR(64);
    DECLARE v_saldo_fis, v_saldo_res DECIMAL(15,4);

    -- 1. GERAÇÃO DE HASH ANTI-RACE CONDITION (LOCK DE PIPELINE)
    SET v_pipeline_hash = SHA2(CONCAT(p_id_item, p_id_lote, p_quantidade, p_id_sessao, p_tipo_fluxo, IFNULL(p_id_referencia_assistencial, 0)), 256);

    START TRANSACTION;

        -- LOCK DE SEMÁFORO: Impede Retries e Double Execution nível Banco
        INSERT INTO estoque_execucao_pipeline (pipeline_hash, estado) VALUES (v_pipeline_hash, 'PROCESSANDO');

        -- LOCK PESSIMISTA DE SALDO
        SELECT qtd_fisica, qtd_reservada INTO v_saldo_fis, v_saldo_res 
        FROM estoque_saldo 
        WHERE id_item = p_id_item AND id_lote = p_id_lote AND id_local = p_id_local_origem 
        FOR UPDATE;

        -- 2. LÓGICA DE LEDGER TRIPLO
        CASE p_tipo_fluxo
            WHEN 'RESERVA' THEN
                -- Médico prescreveu: Aumenta reserva, diminui projetado (Disponibilidade Real)
                IF (v_saldo_fis - v_saldo_res) < p_quantidade THEN
                    ROLLBACK; SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'ERRO_HIS: Saldo projetado insuficiente para reserva.';
                END IF;
                UPDATE estoque_saldo SET qtd_reservada = qtd_reservada + p_quantidade, qtd_projetada = qtd_fisica - (qtd_reservada + p_quantidade)
                WHERE id_item = p_id_item AND id_lote = p_id_lote AND id_local = p_id_local_origem;

            WHEN 'DISPENSACO' THEN
                -- Farmácia enviou para o setor: Diminui físico e diminui reserva (Consumo de prateleira)
                UPDATE estoque_saldo SET qtd_fisica = qtd_fisica - p_quantidade, qtd_reservada = qtd_reservada - p_quantidade
                WHERE id_item = p_id_item AND id_lote = p_id_lote AND id_local = p_id_local_origem;
                
                -- Se houver destino, entra como físico lá
                INSERT INTO estoque_saldo (id_unidade, id_local, id_item, id_lote, qtd_fisica, qtd_projetada, id_sessao_usuario)
                VALUES (p_id_unidade, p_id_local_destino, p_id_item, p_id_lote, p_quantidade, p_quantidade, p_id_sessao)
                ON DUPLICATE KEY UPDATE qtd_fisica = qtd_fisica + p_quantidade, qtd_projetada = qtd_fisica + p_quantidade;

            WHEN 'ADMINISTRACAO' THEN
                -- Enfermeira administrou: Baixa definitiva do físico do setor (Gera gatilho para faturamento)
                UPDATE estoque_saldo SET qtd_fisica = qtd_fisica - p_quantidade, qtd_projetada = qtd_fisica - p_quantidade
                WHERE id_item = p_id_item AND id_lote = p_id_lote AND id_local = p_id_local_origem;
        END CASE;

        -- 3. AUDITORIA SEMÂNTICA (AUDIT EVENT STREAM)
        INSERT INTO estoque_audit_stream (id_movimento, entidade_tipo, evento_tipo, payload_depois)
        VALUES (NULL, 'ESTOQUE', CONCAT('HIS_', p_tipo_fluxo), JSON_OBJECT('item', p_id_item, 'lote', p_id_lote, 'qtd', p_quantidade, 'ref', p_id_referencia_assistencial));

        -- FINALIZA PIPELINE
        UPDATE estoque_execucao_pipeline SET estado = 'CONCLUIDO' WHERE pipeline_hash = v_pipeline_hash;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
