CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_fix_fk_unidade`()
BEGIN

    DECLARE done INT DEFAULT FALSE;
    DECLARE v_table VARCHAR(255);

    -- cursor com suas tabelas
    DECLARE cur CURSOR FOR
        SELECT table_name
        FROM (
            SELECT 'codigo_prefixo_regra' AS table_name UNION
            SELECT 'config_leitos' UNION
            SELECT 'config_locais' UNION
            SELECT 'config_sistema' UNION
            SELECT 'coordenador_estado_global' UNION
            SELECT 'documento_emissao' UNION
            SELECT 'escala_medica' UNION
            SELECT 'escala_plantao' UNION
            SELECT 'escala_plantao_atual' UNION
            SELECT 'escala_profissional' UNION
            SELECT 'estoque_local' UNION
            SELECT 'estoque_movimento' UNION
            SELECT 'estoque_saldo' UNION
            SELECT 'estoque_saldo_central' UNION
            SELECT 'estoque_saldo_master' UNION
            SELECT 'evento_geral' UNION
            SELECT 'faturamento_conta' UNION
            SELECT 'ffa_item' UNION
            SELECT 'funcionario_unidade' UNION
            SELECT 'gaso_solicitacao' UNION
            SELECT 'guardiao_runtime_final' UNION
            SELECT 'internacao_movimentacao' UNION
            SELECT 'ledger_evento_sincronizacao' UNION
            SELECT 'ledger_evento_sincronizacao_local' UNION
            SELECT 'ledger_global_sincronismo' UNION
            SELECT 'painel' UNION
            SELECT 'plantao' UNION
            SELECT 'plantao_escala' UNION
            SELECT 'produtividade_evento' UNION
            SELECT 'reg_export_lote' UNION
            SELECT 'remocao' UNION
            SELECT 'runtime_contexto' UNION
            SELECT 'runtime_edge_evento' UNION
            SELECT 'runtime_invariant_log' UNION
            SELECT 'runtime_sync_log' UNION
            SELECT 'sala_notificacao' UNION
            SELECT 'senha_sequencia' UNION
            SELECT 'servico_agendamento' UNION
            SELECT 'sessao_usuario' UNION
            SELECT 'setor' UNION
            SELECT 'totem' UNION
            SELECT 'tv_rotativo' UNION
            SELECT 'usuario_contexto' UNION
            SELECT 'usuario_unidade' UNION
            SELECT 'viatura'
        ) t;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    OPEN cur;

    loop_tables: LOOP

        FETCH cur INTO v_table;
        IF done THEN
            LEAVE loop_tables;
        END IF;

        -- 1. NORMALIZA DADOS
        SET @sql1 = CONCAT('
            UPDATE ', v_table, '
            SET id_unidade = 1
            WHERE id_unidade IS NULL
               OR id_unidade <= 0
               OR id_unidade REGEXP "[^0-9]"
        ');

        PREPARE stmt FROM @sql1;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;

        -- 2. AJUSTA TIPO
        SET @sql2 = CONCAT('
            ALTER TABLE ', v_table, '
            MODIFY COLUMN id_unidade BIGINT UNSIGNED NOT NULL
        ');

        PREPARE stmt FROM @sql2;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;

        -- 3. CRIA FK SE NÃO EXISTIR
        SET @fk = CONCAT('fk_', v_table, '_unidade');

        SET @check_fk = CONCAT('
            SELECT COUNT(*) INTO @fk_exists
            FROM INFORMATION_SCHEMA.TABLE_CONSTRAINTS
            WHERE CONSTRAINT_SCHEMA = DATABASE()
              AND TABLE_NAME = "', v_table, '"
              AND CONSTRAINT_NAME = "', @fk, '"
        ');

        PREPARE stmt FROM @check_fk;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;

        IF @fk_exists = 0 THEN

            SET @sql3 = CONCAT('
                ALTER TABLE ', v_table, '
                ADD CONSTRAINT ', @fk, '
                FOREIGN KEY (id_unidade)
                REFERENCES unidade(id_unidade)
            ');

            PREPARE stmt FROM @sql3;
            EXECUTE stmt;
            DEALLOCATE PREPARE stmt;

        END IF;

    END LOOP;

    CLOSE cur;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_fluxo_estoque` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_fluxo_estoque`(
    IN p_id_unidade BIGINT,
    IN p_id_local BIGINT,
    IN p_contexto VARCHAR(30),
    IN p_id_item BIGINT,
    IN p_id_lote BIGINT,
    IN p_quantidade DECIMAL(15,4),
    IN p_acao ENUM('RESERVAR', 'DISPENSAR', 'ESTORNAR_RESERVA'),
    IN p_id_referencia BIGINT,
    IN p_id_sessao BIGINT
)
BEGIN
    DECLARE v_hash CHAR(64);
    DECLARE v_fis, v_res DECIMAL(15,4);

    -- 1. VALIDAÇÃO DE SESSÃO (CORE REQUIREMENT)
    IF p_id_sessao IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'LEI_IMUTAVEL: Sessao obrigatoria';
    END IF;

    -- 2. HASH IDEMPOTENTE (ANTI-REPLAY)
    SET v_hash = SHA2(CONCAT(p_id_unidade, p_id_local, p_id_item, p_id_lote, p_quantidade, p_acao, p_id_referencia, p_id_sessao), 256);

    -- 3. LOCK DE PIPELINE COM LEASE (ANTI-DUPLA EXECUÇÃO)
    INSERT INTO estoque_execucao_pipeline (pipeline_hash, estado, lease_expira_em)
    VALUES (v_hash, 'PROCESSANDO', NOW() + INTERVAL 30 SECOND)
    ON DUPLICATE KEY UPDATE lease_expira_em = NOW() + INTERVAL 30 SECOND;

    START TRANSACTION;

        -- 4. MATERIALIZAÇÃO DE SALDO (GARANTE EXISTÊNCIA NO RUNTIME)
        INSERT INTO estoque_saldo (id_unidade, id_local, contexto_tipo, id_item, id_lote, id_sessao_usuario)
        VALUES (p_id_unidade, p_id_local, p_contexto, p_id_item, p_id_lote, p_id_sessao)
        ON DUPLICATE KEY UPDATE id_saldo = id_saldo;

        -- 5. LOCK PESSIMISTA DO ESTADO ATUAL
        SELECT qtd_fisica, qtd_reservada INTO v_fis, v_res
        FROM estoque_saldo
        WHERE id_unidade = p_id_unidade AND id_local = p_id_local 
        AND id_item = p_id_item AND id_lote = p_id_lote
        FOR UPDATE;

        -- 6. MOTOR LOGÍSTICO (DECISÃO ATÔMICA)
        CASE p_acao
            WHEN 'RESERVAR' THEN
                IF (v_fis - v_res) < p_quantidade THEN
                    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'SALDO_PROJETADO_INSUFICIENTE';
                END IF;
                UPDATE estoque_saldo SET qtd_reservada = qtd_reservada + p_quantidade
                WHERE id_unidade = p_id_unidade AND id_local = p_id_local AND id_item = p_id_item AND id_lote = p_id_lote;

            WHEN 'DISPENSAR' THEN
                IF v_fis < p_quantidade THEN
                    SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'SALDO_FISICO_INSUFICIENTE';
                END IF;
                UPDATE estoque_saldo 
                SET qtd_fisica = qtd_fisica - p_quantidade, 
                    qtd_reservada = GREATEST(qtd_reservada - p_quantidade, 0)
                WHERE id_unidade = p_id_unidade AND id_local = p_id_local AND id_item = p_id_item AND id_lote = p_id_lote;

            WHEN 'ESTORNAR_RESERVA' THEN
                UPDATE estoque_saldo SET qtd_reservada = GREATEST(qtd_reservada - p_quantidade, 0)
                WHERE id_unidade = p_id_unidade AND id_local = p_id_local AND id_item = p_id_item AND id_lote = p_id_lote;
        END CASE;

        -- 7. AUDITORIA SEMÂNTICA (IMUTABILIDADE DO EVENTO)
        INSERT INTO estoque_audit_stream (id_referencia_externa, entidade_tipo, evento_tipo, payload, hash_pipeline)
        VALUES (p_id_referencia, 'ESTOQUE', p_acao, JSON_OBJECT('qtd', p_quantidade, 'sessao', p_id_sessao, 'contexto', p_contexto), v_hash);

        -- 8. FINALIZAÇÃO DO ESTADO DO PIPELINE
        UPDATE estoque_execucao_pipeline SET estado = 'CONCLUIDO' WHERE pipeline_hash = v_hash;

    COMMIT;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_fluxo_executor_matriz` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb3_general_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_fluxo_executor_matriz`(
    IN p_estado_atual VARCHAR(60),
    IN p_evento VARCHAR(60),
    IN p_id_perfil BIGINT,
    IN p_contexto VARCHAR(50),
    IN p_id_sistema BIGINT,
    IN p_id_sessao_usuario BIGINT,
    OUT p_estado_destino VARCHAR(60)
)
    SQL SECURITY INVOKER
BEGIN

    DECLARE v_destino VARCHAR(60);

    /* ===============================
       Consulta determinística da matriz
    =============================== */

    SELECT ftd.estado_destino
    INTO v_destino
    FROM fluxo_transicao_matriz ftd
    WHERE ftd.estado_origem = p_estado_atual
      AND ftd.evento = p_evento
      AND ftd.id_perfil = p_id_perfil
      AND ftd.contexto = p_contexto
      AND ftd.id_sistema = p_id_sistema
      AND ftd.ativo = 1
    ORDER BY ftd.prioridade DESC
    LIMIT 1;

    IF v_destino IS NULL THEN

        INSERT INTO auditoria_evento(
            id_sessao_usuario,
            evento,
            sucesso,
            descricao
        )
        VALUES(
            p_id_sessao_usuario,
            'TRANSICAO_BLOQUEADA',
            0,
            CONCAT(
                'Origem=',p_estado_atual,
                '|Evento=',p_evento,
                '|Perfil=',p_id_perfil
            )
        );

        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Transição inválida pela matriz de fluxo';

    END IF;

    SET p_estado_destino = v_destino;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
