CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_kernel_identity_chain_register`(
    IN p_id_tenant BIGINT,
    IN p_id_usuario BIGINT,
    IN p_id_sessao BIGINT,
    IN p_id_dispositivo BIGINT,
    IN p_estado VARCHAR(60),
    IN p_ip VARCHAR(45)
)
    SQL SECURITY INVOKER
BEGIN

    DECLARE v_fingerprint CHAR(64);

    SET v_fingerprint = SHA2(
        CONCAT_WS('|',
            IFNULL(p_id_tenant,''),
            IFNULL(p_id_usuario,''),
            IFNULL(p_id_sessao,''),
            IFNULL(p_id_dispositivo,''),
            IFNULL(p_estado,'')
        ),
    256);

    INSERT IGNORE INTO kernel_identity_trust_chain (
        id_tenant,
        id_usuario,
        id_sessao,
        id_dispositivo,
        ip_origem,
        fingerprint_runtime,
        estado_runtime
    )
    VALUES (
        p_id_tenant,
        p_id_usuario,
        p_id_sessao,
        p_id_dispositivo,
        p_ip,
        v_fingerprint,
        p_estado
    );

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
