DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_kernel_writer_unlock`(
    IN p_lock_id BIGINT
)
BEGIN
    DELETE FROM runtime_kernel_locks
    WHERE id = p_lock_id;
END ;;
