/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_master_dispatcher`(
    IN p_id_sessao BIGINT,
    IN p_uuid_transacao CHAR(36),
    IN p_dominio VARCHAR(50),
    IN p_acao VARCHAR(100),
    IN p_id_referencia BIGINT,
    IN p_payload JSON
)
    SQL SECURITY INVOKER
main: BEGIN

    -- ==========================================
    -- 1. DECLARAÇÕES
    -- ==========================================
    DECLARE v_id_usuario, v_id_unidade, v_id_saas, v_id_local, v_id_painel, v_id_perfil BIGINT;
    DECLARE v_ativo TINYINT;
    DECLARE v_nome_sp VARCHAR(120);
    DECLARE v_uuid CHAR(36);
    DECLARE v_hash CHAR(64);
    DECLARE v_id_evento BIGINT DEFAULT 0;
    DECLARE v_estado_atual, v_estado_destino VARCHAR(50);
    DECLARE v_msg TEXT;
    
    DECLARE v_id_atendimento_vinculo BIGINT;
    DECLARE v_ip VARCHAR(45);
    DECLARE v_device VARCHAR(255);

    -- ==========================================
    -- 2. HANDLER GLOBAL
    -- ==========================================
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 v_msg = MESSAGE_TEXT;
        INSERT INTO erro_evento (
            id_sessao_usuario, dominio, tipo_evento, mensagem_erro, payload, metadata, uuid_transacao
        ) VALUES (
            p_id_sessao, p_dominio, p_acao, v_msg, p_payload, 
            JSON_OBJECT('executor', v_nome_sp, 'hash', v_hash), v_uuid
        );
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = v_msg;
    END;

    -- ==========================================
    -- 3. INIT & CONTEXTO
    -- ==========================================
    SET v_uuid = IFNULL(p_uuid_transacao, UUID());
    SET p_payload = IFNULL(p_payload, JSON_OBJECT());
    SET v_hash = SHA2(CONCAT(v_uuid, CAST(p_payload AS CHAR)), 256);

    SELECT id_usuario, id_unidade, id_saas_entidade, id_local, id_painel, id_perfil, ativo
    INTO v_id_usuario, v_id_unidade, v_id_saas, v_id_local, v_id_painel, v_id_perfil, v_ativo
    FROM sessao_usuario WHERE id_sessao_usuario = p_id_sessao LIMIT 1;

    IF v_id_usuario IS NULL OR v_ativo = 0 THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'SESSAO_INVALIDA';
    END IF;

    SET v_ip = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.ip_origem'));
    SET v_device = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.device_info'));

    -- ==========================================
    -- 4. IDEMPOTÊNCIA
    -- ==========================================
    IF p_uuid_transacao IS NOT NULL AND EXISTS (
        SELECT 1 FROM atendimento_evento WHERE uuid_transacao = p_uuid_transacao LIMIT 1
    ) THEN
        SELECT JSON_OBJECT('status','SUCCESS','idempotente',1,'uuid', v_uuid) AS result;
        LEAVE main;
    END IF;

    -- ==========================================
    -- 5. RESOLVER EXECUTOR
    -- ==========================================
    SELECT nome_procedure INTO v_nome_sp FROM permissao
    WHERE codigo = CONCAT(UPPER(p_dominio), '.', UPPER(p_acao)) AND ativo = 1 LIMIT 1;

    IF v_nome_sp IS NULL OR v_nome_sp NOT LIKE 'sp_executor_%' THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'EXECUTOR_INVALIDO_OU_NAO_MAPEADO';
    END IF;

    -- ==========================================
    -- 6. RESOLVER VÍNCULO DE ATENDIMENTO
    -- ==========================================
    IF p_id_referencia > 0 THEN
        SELECT id_atendimento INTO v_id_atendimento_vinculo
        FROM atendimento_vinculo 
        WHERE id_ffa = p_id_referencia AND ativo = 1 LIMIT 1;

        SET p_payload = JSON_SET(p_payload, 
            '$.id_atendimento', v_id_atendimento_vinculo,
            '$.id_saas_entidade', v_id_saas,
            '$.id_unidade', v_id_unidade
        );
    END IF;

    -- ==========================================
    -- 7. REGISTRO NO LEDGER
    -- ==========================================
    CALL sp_master_registrar_evento(
        p_id_sessao, p_dominio, p_acao, p_id_referencia, p_payload,
        JSON_OBJECT('id_saas', v_id_saas, 'id_unidade', v_id_unidade, 'ip', v_ip, 'device', v_device),
        v_uuid, v_id_evento
    );

    -- ==========================================
    -- 8. EXECUÇÃO DINÂMICA (CORREÇÃO AQUI)
    -- ==========================================
    -- Passamos os valores para variáveis de usuário (@) para o PREPARE não falhar
    SET @p_sessao = p_id_sessao;
    SET @p_acao = p_acao;
    SET @p_ref = p_id_referencia;
    SET @p_pay = p_payload;

    SET @sql_call = CONCAT('CALL ', v_nome_sp, '(?, ?, ?, ?)');
    
    PREPARE stmt FROM @sql_call;
    EXECUTE stmt USING @p_sessao, @p_acao, @p_ref, @p_pay;
    DEALLOCATE PREPARE stmt;

    -- ==========================================
    -- 9. RETORNO PADRÃO
    -- ==========================================
    SELECT JSON_OBJECT(
        'status', 'SUCCESS',
        'uuid', v_uuid,
        'id_evento', v_id_evento,
        'executor', v_nome_sp,
        'timestamp', NOW()
    ) AS result;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_master_ffa_movimentar` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_master_ffa_movimentar`(
    IN p_id_sessao BIGINT,
    IN p_id_usuario BIGINT,
    IN p_id_ffa INT,
    IN p_novo_status VARCHAR(50),
    OUT p_resultado JSON
)
    SQL SECURITY INVOKER
proc: BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN
        GET DIAGNOSTICS CONDITION 1 @msg = MESSAGE_TEXT;
        ROLLBACK;
        SET p_resultado = JSON_OBJECT('sucesso', FALSE, 'mensagem', @msg);
    END;

    START TRANSACTION;

    -- Atualiza o workflow (FFA)
    UPDATE ffa SET status = p_novo_status, atualizado_em = NOW() WHERE id_ffa = p_id_ffa;

    -- Registro no Ledger de Movimentação (Workflow Evento)
    INSERT INTO workflow_ffa_evento (id_ffa, tipo_evento, detalhe, id_sessao_usuario)
    VALUES (p_id_ffa, 'STATUS_CHANGE', CONCAT('Status alterado para: ', p_novo_status), p_id_sessao);

    COMMIT;
    SET p_resultado = JSON_OBJECT('sucesso', TRUE, 'mensagem', 'Fluxo atualizado');
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_master_login` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_master_login`(
    IN p_acao VARCHAR(100),
    IN p_payload JSON,
    OUT p_resultado JSON,
    OUT p_sucesso BOOLEAN,
    OUT p_mensagem TEXT
)
    SQL SECURITY INVOKER
proc: BEGIN

    -- ==========================================
    -- DECLARAÇÕES
    -- ==========================================
    DECLARE v_id_usuario BIGINT;
    DECLARE v_login VARCHAR(120);
    DECLARE v_senha_hash VARCHAR(255);
    DECLARE v_ativo TINYINT;

    DECLARE v_id_sessao BIGINT;
    DECLARE v_uuid_sessao CHAR(36);

    DECLARE v_token_jwt VARCHAR(512);
    DECLARE v_refresh_token VARCHAR(512);

    DECLARE v_ip VARCHAR(45);
    DECLARE v_device VARCHAR(255);
    DECLARE v_fingerprint VARCHAR(255);

    DECLARE v_id_unidade BIGINT;
    DECLARE v_id_local BIGINT;
    DECLARE v_id_perfil BIGINT;

    DECLARE v_tentativas INT DEFAULT 0;
    DECLARE v_tem_permissao INT DEFAULT 1;

    SET p_sucesso = FALSE;
    SET p_mensagem = '';
    SET p_resultado = JSON_OBJECT();

    -- ==========================================
    -- AUTH.LOGIN.REQUEST
    -- ==========================================
    IF p_acao = 'AUTH.LOGIN.REQUEST' THEN

        SET v_login         = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.login'));
        SET v_token_jwt     = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.token_jwt'));
        SET v_refresh_token = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.refresh_token'));
        SET v_ip            = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.ip'));
        SET v_device        = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.device'));
        SET v_fingerprint   = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.fingerprint'));

        IF v_login IS NULL THEN
            SET p_mensagem = 'LOGIN_OBRIGATORIO';
            LEAVE proc;
        END IF;

        SELECT id_usuario, senha, ativo
        INTO v_id_usuario, v_senha_hash, v_ativo
        FROM usuario
        WHERE login = v_login
        LIMIT 1;

        IF v_id_usuario IS NULL THEN
            SET p_mensagem = 'USUARIO_NAO_ENCONTRADO';
            LEAVE proc;
        END IF;

        IF v_ativo <> 1 THEN
            SET p_mensagem = 'USUARIO_INATIVO';
            LEAVE proc;
        END IF;

        SELECT COUNT(*) INTO v_tentativas
        FROM login_tentativa
        WHERE id_usuario = v_id_usuario
          AND sucesso = 0
          AND criado_em >= NOW() - INTERVAL 15 MINUTE;

        IF v_tentativas >= 5 THEN
            SET p_mensagem = 'USUARIO_BLOQUEADO_TEMP';
            LEAVE proc;
        END IF;

        IF v_token_jwt IS NULL THEN
            SET p_mensagem = 'TOKEN_OBRIGATORIO';
            LEAVE proc;
        END IF;

        SET v_uuid_sessao = UUID();

        INSERT INTO sessao_usuario (
            uuid_sessao,
            id_usuario,
            id_sistema,
            id_unidade,
            id_local,
            id_perfil,
            token_jwt,
            refresh_token,
            ip_origem,
            user_agent,
            device_fingerprint,
            iniciado_em,
            expira_em,
            criado_em,
            ativo
        ) VALUES (
            v_uuid_sessao,
            v_id_usuario,
            1,
            NULL,
            NULL,
            NULL,
            v_token_jwt,
            v_refresh_token,
            v_ip,
            v_device,
            v_fingerprint,
            NOW(6),
            DATE_ADD(NOW(6), INTERVAL 24 HOUR),
            NOW(6),
            1
        );

        SET v_id_sessao = LAST_INSERT_ID();

        SET p_resultado = JSON_OBJECT(
            'sessao', JSON_OBJECT(
                'id_sessao_usuario', v_id_sessao,
                'uuid_sessao', v_uuid_sessao,
                'contexto_definido', FALSE
            )
        );

        SET p_sucesso = TRUE;
        SET p_mensagem = 'LOGIN_OK';

    -- ==========================================
    -- AUTH.CONTEXTO.GET
    -- ==========================================
    ELSEIF p_acao = 'AUTH.CONTEXTO.GET' THEN

        SET v_id_sessao = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_sessao'));

        SELECT id_usuario INTO v_id_usuario
        FROM sessao_usuario
        WHERE id_sessao_usuario = v_id_sessao;

        SET p_resultado = JSON_OBJECT(
            'unidades', (
                SELECT JSON_ARRAYAGG(JSON_OBJECT('id_unidade', u.id_unidade, 'nome', u.nome))
                FROM usuario_unidade uu
                JOIN unidade u ON u.id_unidade = uu.id_unidade
                WHERE uu.id_usuario = v_id_usuario
            ),
            'locais', (
                SELECT JSON_ARRAYAGG(JSON_OBJECT(
                    'id_local', l.id_local,
                    'nome', l.nome
                ))
                FROM usuario_local ul
                JOIN local l ON l.id_local = ul.id_local
                WHERE ul.id_usuario = v_id_usuario
            ),
            'perfis', (
                SELECT JSON_ARRAYAGG(JSON_OBJECT('id_perfil', p.id_perfil, 'nome', p.nome))
                FROM usuario_perfil up
                JOIN perfil p ON p.id_perfil = up.id_perfil
                WHERE up.id_usuario = v_id_usuario
            )
        );

        SET p_sucesso = TRUE;
        SET p_mensagem = 'CONTEXTOS';

    -- ==========================================
    -- AUTH.CONTEXTO.SET
    -- ==========================================
    ELSEIF p_acao = 'AUTH.CONTEXTO.SET' THEN

        SET v_id_sessao  = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_sessao'));
        SET v_id_unidade = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_unidade'));
        SET v_id_local   = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_local'));
        SET v_id_perfil  = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_perfil'));

        UPDATE sessao_usuario
        SET 
            id_unidade = v_id_unidade,
            id_local   = v_id_local,
            id_perfil  = v_id_perfil,
            contexto_definido_em = NOW(6)
        WHERE id_sessao_usuario = v_id_sessao;

        SET p_resultado = JSON_OBJECT(
            'contexto_definido', TRUE
        );

        SET p_sucesso = TRUE;
        SET p_mensagem = 'CONTEXTO_OK';

    -- ==========================================
    -- AUTH.SESSAO.ASSERT
    -- ==========================================
    ELSEIF p_acao = 'AUTH.SESSAO.ASSERT' THEN

        SET v_id_sessao = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_sessao'));

        SELECT id_usuario, id_unidade, id_local, id_perfil
        INTO v_id_usuario, v_id_unidade, v_id_local, v_id_perfil
        FROM sessao_usuario
        WHERE id_sessao_usuario = v_id_sessao AND ativo = 1;

        IF v_id_usuario IS NULL THEN
            SET p_mensagem = 'SESSAO_INVALIDA';
            LEAVE proc;
        END IF;

        IF v_id_unidade IS NULL THEN
            SET p_mensagem = 'CONTEXTO_NAO_DEFINIDO';
            LEAVE proc;
        END IF;

        SET p_resultado = JSON_OBJECT(
            'id_usuario', v_id_usuario,
            'id_unidade', v_id_unidade,
            'id_local', v_id_local,
            'id_perfil', v_id_perfil
        );

        SET p_sucesso = TRUE;
        SET p_mensagem = 'OK';

    -- ==========================================
    -- AUTH.LOGOUT.REQUEST
    -- ==========================================
    ELSEIF p_acao = 'AUTH.LOGOUT.REQUEST' THEN

        SET v_id_sessao = JSON_UNQUOTE(JSON_EXTRACT(p_payload, '$.id_sessao'));

        UPDATE sessao_usuario
        SET 
            ativo = 0,
            revogado = 1,
            finalizado_em = NOW(6),
            motivo_finalizacao = 'LOGOUT'
        WHERE id_sessao_usuario = v_id_sessao;

        SET p_sucesso = TRUE;
        SET p_mensagem = 'LOGOUT_OK';

    ELSE
        SET p_mensagem = 'ACAO_INVALIDA';
    END IF;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_master_orquestradora` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_master_orquestradora`(
    IN p_id_sessao BIGINT,
    IN p_modulo VARCHAR(50),
    IN p_acao VARCHAR(50),
    IN p_payload JSON,
    OUT p_resultado JSON,
    OUT p_sucesso BOOLEAN,
    OUT p_mensagem TEXT
)
    SQL SECURITY INVOKER
main: BEGIN

    -- ==========================================
    -- 1. DECLARAÇÕES
    -- ==========================================
    DECLARE v_id_usuario BIGINT;
    DECLARE v_id_unidade BIGINT;
    DECLARE v_erro_msg TEXT DEFAULT '';

    -- Handler global de erro
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1 v_erro_msg = MESSAGE_TEXT;
        SET p_resultado = JSON_OBJECT();
        SET p_sucesso = FALSE;
        SET p_mensagem = v_erro_msg;

        INSERT INTO auditoria_evento(
            id_usuario, entidade, id_entidade, acao, detalhe, criado_em
        ) VALUES (
            v_id_usuario, 'orquestradora', NULL, CONCAT('ERRO_', p_modulo),
            JSON_OBJECT('acao', p_acao, 'payload', p_payload, 'erro', v_erro_msg),
            NOW(6)
        );
    END;

    -- Inicializa saída
    SET p_sucesso = FALSE;
    SET p_resultado = JSON_ARRAY();
    SET p_mensagem = '';

    -- ==========================================
    -- 2. VALIDAÇÃO DE SESSÃO
    -- ==========================================
    IF p_modulo NOT IN ('LOGIN') THEN
        SELECT id_usuario, id_unidade INTO v_id_usuario, v_id_unidade
        FROM sessao_usuario
        WHERE id_sessao_usuario = p_id_sessao AND ativo = 1
        LIMIT 1;

        IF v_id_usuario IS NULL THEN
            SET p_mensagem = 'SESSAO_INVALIDA_OU_EXPIRADA';
            LEAVE main;
        END IF;
    END IF;

    -- ==========================================
    -- 3. DISPATCH PRINCIPAL
    -- ==========================================
    CASE p_modulo

        WHEN 'LOGIN' THEN
            CALL sp_master_login(
                p_acao,
                p_payload,
                p_resultado,
                p_sucesso,
                p_mensagem
            );

        WHEN 'ASSISTENCIAL' THEN
            CALL sp_master_assistencial(
                v_id_usuario,
                p_acao,
                p_payload,
                p_resultado,
                p_sucesso,
                p_mensagem
            );

        WHEN 'ESTOQUE' THEN
            CALL sp_master_estoque(
                v_id_usuario,
                p_acao,
                p_payload,
                p_resultado,
                p_sucesso,
                p_mensagem
            );

        WHEN 'FATURAMENTO' THEN
            CALL sp_master_faturamento(
                v_id_usuario,
                p_acao,
                p_payload,
                p_resultado,
                p_sucesso,
                p_mensagem
            );

        WHEN 'PACIENTE'
          OR 'PACIENTE_TIMELINE'
          OR 'TRIAGEM'
          OR 'FILA_ESPERA'
          OR 'USUARIO'
          OR 'PERMISSAO_USUARIO' THEN

            CALL sp_master_query_dispatcher(
                p_id_sessao,
                p_modulo,
                p_payload,
                p_resultado,
                p_sucesso,
                p_mensagem
            );

        ELSE
            SET p_mensagem = 'MODULO_INVALIDO';
            SET p_sucesso = FALSE;

    END CASE;

    -- ==========================================
    -- 4. LOGGING PADRÃO
    -- ==========================================
    IF p_sucesso = TRUE THEN
        INSERT INTO auditoria_evento(
            id_usuario, entidade, id_entidade, acao, detalhe, criado_em
        ) VALUES (
            v_id_usuario, 'orquestradora', NULL, CONCAT('SUCCESS_', p_modulo),
            JSON_OBJECT('acao', p_acao, 'payload', p_payload, 'resultado', p_resultado),
            NOW(6)
        );
    END IF;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
