CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_recepcao_complementar_e_abrir_ffa`(
    IN p_id_sessao_usuario BIGINT,
    IN p_id_senha BIGINT,
    IN p_id_paciente BIGINT
)
    SQL SECURITY INVOKER
BEGIN
    DECLARE v_id_ffa BIGINT;

    CALL sp_sessao_assert(p_id_sessao_usuario);

    START TRANSACTION;

    INSERT INTO atendimento_ffa (
        id_paciente,
        id_sessao_abertura,
        criado_em
    )
    VALUES (
        p_id_paciente,
        p_id_sessao_usuario,
        NOW()
    );

    SET v_id_ffa = LAST_INSERT_ID();

    UPDATE senha
    SET id_ffa = v_id_ffa,
        status = 'CONCLUIDA',
        finalizada_em = NOW()
    WHERE id = p_id_senha;

    INSERT INTO atendimento_estado_ativo (
        id_ffa,
        estado_atual,
        atualizado_em
    )
    VALUES (
        v_id_ffa,
        'AGUARDANDO_TRIAGEM',
        NOW()
    );

    COMMIT;
END ;;
