CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_senha_cancelar`(
    IN p_id_sessao_usuario BIGINT,
    IN p_id_senha BIGINT
)
    SQL SECURITY INVOKER
BEGIN

    CALL sp_sessao_assert(p_id_sessao_usuario);

    UPDATE senha 
    SET status = 'CANCELADA',
        finalizada_em = NOW()
    WHERE id = p_id_senha;

END ;;
