/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_senha_chamar`(
    IN p_id_sessao_usuario BIGINT,
    IN p_id_unidade BIGINT,
    IN p_id_local BIGINT,
    IN p_id_saas_entidade BIGINT
)
    SQL SECURITY INVOKER
BEGIN

    DECLARE v_id_senha BIGINT;

    START TRANSACTION;

    /* Seleciona próxima senha da fila universal */

    SELECT id_senha
    INTO v_id_senha
    FROM senha
    WHERE
        id_saas_entidade = p_id_saas_entidade
        AND id_unidade = p_id_unidade
        AND (p_id_local IS NULL OR id_local = p_id_local)
        AND cancelado = FALSE
        AND executado_em IS NULL
    ORDER BY prioridade DESC,
             ordem_fila ASC,
             criado_em ASC
    LIMIT 1
    FOR UPDATE;

    /* Atualiza estado operacional */

    IF v_id_senha IS NOT NULL THEN

        UPDATE senha
        SET
            chamada_sequencial = chamada_sequencial + 1,
            chamada_em = CURRENT_TIMESTAMP(6),
            id_sessao_usuario = p_id_sessao_usuario
        WHERE id_senha = v_id_senha;

    END IF;

    COMMIT;

    SELECT * FROM senha WHERE id_senha = v_id_senha;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_senha_chamar_proxima` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_senha_chamar_proxima`(
    IN p_id_sessao_usuario BIGINT,
    IN p_id_local_operacional BIGINT
)
    SQL SECURITY INVOKER
main: BEGIN

    DECLARE v_id_senha BIGINT;
    DECLARE v_id_usuario BIGINT;

    CALL sp_sessao_assert(p_id_sessao_usuario);

    SELECT id_usuario 
    INTO v_id_usuario
    FROM sessao_usuario 
    WHERE id_sessao_usuario = p_id_sessao_usuario;

    START TRANSACTION;

    SELECT id 
    INTO v_id_senha 
    FROM senha 
    WHERE status = 'EMITIDA'
      AND id_local_operacional = p_id_local_operacional
    ORDER BY prioridade DESC, criada_em ASC
    LIMIT 1
    FOR UPDATE;

    IF v_id_senha IS NOT NULL THEN
        UPDATE senha 
        SET status = 'CHAMANDO',
            id_usuario_chamada = v_id_usuario,
            chamada_em = NOW()
        WHERE id = v_id_senha;

        SELECT * FROM senha WHERE id = v_id_senha;
    END IF;

    COMMIT;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_senha_chamar_setor` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_senha_chamar_setor`(
    IN p_id_sessao_usuario BIGINT,
    IN p_id_senha BIGINT
)
    SQL SECURITY INVOKER
BEGIN
    DECLARE v_id_usuario BIGINT;
    DECLARE v_id_local BIGINT;
    DECLARE v_status VARCHAR(30);

    -- 1️⃣ Valida sessão
    CALL sp_sessao_assert(p_id_sessao_usuario);

    -- 2️⃣ Obtém contexto da sessão
    SELECT id_usuario, id_local_operacional
    INTO v_id_usuario, v_id_local
    FROM sessao_usuario
    WHERE id_sessao_usuario = p_id_sessao_usuario;

    -- 3️⃣ Obtém status atual da senha
    SELECT status
    INTO v_status
    FROM senha
    WHERE id = p_id_senha
      AND id_local_operacional = v_id_local
    FOR UPDATE;

    -- 4️⃣ Só permite chamar se estiver EMITIDA ou NAO_COMPARECEU
    IF v_status IN ('EMITIDA','NAO_COMPARECEU') THEN

        UPDATE senha
        SET status = 'CHAMANDO',
            id_usuario_chamada = v_id_usuario,
            chamada_em = NOW()
        WHERE id = p_id_senha;

    END IF;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
