CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_sessao_contexto_get`(
    IN p_id_sessao_usuario BIGINT
)
BEGIN
    CALL sp_sessao_assert(p_id_sessao_usuario);

    SELECT
        su.id_sessao_usuario,
        su.id_usuario,
        su.id_sistema,
        su.id_unidade,
        su.id_local_operacional,
        su.ip_acesso,
        su.user_agent,
        su.iniciado_em,
        su.expira_em,
        su.ativo
    FROM sessao_usuario su
    WHERE su.id_sessao_usuario = p_id_sessao_usuario;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `sp_sessao_contexto_set` */;
