CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_usuario_refresh_token_emitir`(
    IN p_id_usuario BIGINT,
    IN p_token VARCHAR(255),
    IN p_expira_em DATETIME
)
BEGIN
    INSERT INTO usuario_refresh_token(
        id_usuario,
        token,
        expira_em,
        revogado
    )
