CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_usuario_refresh_token_revogar`(
    IN p_token VARCHAR(255)
)
BEGIN
    UPDATE usuario_refresh_token
       SET revogado = 1
     WHERE token = p_token;
END ;;
